import React from 'react';

const AdminDashboard = () => {
    const allReviews = [
        { id: 1, dealer_id: 1, user: "Kelebogile M.", comment: "Great stock!", status: "Approved" },
        { id: 2, dealer_id: 2, user: "Pieter S.", comment: "Service was slow.", status: "Pending" }
    ];

    return (
        <div className="dashboard-container">
            <h1 className="cyber-title">Admin Moderation</h1>
            <div className="glass-card" style={{marginTop: '20px', padding: '20px'}}>
                <table style={{width: '100%', color: 'white', borderCollapse: 'collapse'}}>
                    <thead>
                        <tr style={{color: '#E0B0FF', borderBottom: '1px solid #444'}}>
                            <th>Dealer ID</th>
                            <th>User</th>
                            <th>Comment</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {allReviews.map(review => (
                            <tr key={review.id} style={{borderBottom: '1px solid #222'}}>
                                <td style={{padding: '15px'}}>{review.dealer_id}</td>
                                <td>{review.user}</td>
                                <td>{review.comment}</td>
                                <td><button className="cyber-button" style={{fontSize: '0.7rem'}}>Delete</button></td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default AdminDashboard;
